// m2-sig-tests/src/main.nr
//
// Standalone Noir unit tests for the M2 secp256k1 ownership proof circuit.
//
// These tests verify that std::ecdsa_secp256k1::verify_signature behaves
// correctly for the M2 signature scheme used in cast_vote_babylon_v2:
//
//   challenge = sha256(title_hash_encoded[32] || root_bytes[32])
//   sig_valid = ecdsa_secp256k1::verify_signature(pubkey_x, pubkey_y, sig, challenge)
//
// Test vectors generated by Python (ecdsa library, RFC 6979 deterministic):
//   Private key: 1 (secp256k1 generator point G)
//   pubkey_x = 79be667ef9dcbbac55a06295ce870b07029bfcdb2dce28d959f2815b16f81798
//   pubkey_y = 483ada7726a3c4655da4fbfc0e1108a8fd17b448a68554199c47d08ffb10d4b8
//   challenge = sha256(0x00*64) = f5a5fd42d16a20302798ef6ed309979b43003d2320d9f0e8ea9831a92759fb4b
//   sig_r     = 89ef25e7181bfb53cd4ecc8f0c12ed103fc4538b155885e5ee2998cc1257fdde
//   sig_s     = b3ee5d833686b434958c65c7e30e9ed06891d2527c51344c8d73fe4f5a5fde8c
//   sig (r||s) = sig_r ++ sig_s (64 bytes)
//
// Run: cd m2-sig-tests && /root/.nargo/bin/nargo test

use sha256::sha256_var;
use std::ecdsa_secp256k1;
use keccak256::keccak256;

// ---------------------------------------------------------------------------
// M2 benchmark main — full EIP-191 ownership proof path
// ---------------------------------------------------------------------------
//
// This is the complete in-circuit M2 verification path as executed by
// cast_vote_babylon_v2, stripped of Merkle membership and storage calls.
// Running `nargo info` on this binary reports the ACIR opcode count for
// the three cryptographic steps: SHA-256 challenge, keccak256 EIP-191
// wrapping, and secp256k1 signature verification.
//
// Steps:
//   1. challenge = sha256(title_hash_bytes32[32] || merkle_root_bytes32[32])
//   2. eip191_prefix = "\x19Ethereum Signed Message:\n32" (28 bytes)
//   3. msg_hash     = keccak256(eip191_prefix[28] || challenge[32])
//   4. sig_valid    = ecdsa_secp256k1::verify_signature(pubkey_x, pubkey_y, sig, msg_hash)
//   5. assert(sig_valid)
//
// Prover.toml supplies the private witnesses (test vectors = secp256k1
// generator point G, privkey=1, with the encoding-fix title_hash).
fn main(
    pubkey_x: [u8; 32],
    pubkey_y: [u8; 32],
    sig: [u8; 64],
    title_hash_bytes32: [u8; 32],
    merkle_root_bytes32: [u8; 32],
) {
    // Step 1: vote-specific challenge (SHA-256)
    let mut challenge_input = [0u8; 64];
    for i in 0..32 { challenge_input[i] = title_hash_bytes32[i]; }
    for i in 0..32 { challenge_input[32 + i] = merkle_root_bytes32[i]; }
    let challenge = sha256_var(challenge_input, 64);

    // Step 2+3: EIP-191 wrapping (keccak256)
    // "\x19Ethereum Signed Message:\n32" in ASCII (28 bytes)
    let eip191_prefix: [u8; 28] = [
        0x19, 0x45, 0x74, 0x68, 0x65, 0x72, 0x65, 0x75,
        0x6d, 0x20, 0x53, 0x69, 0x67, 0x6e, 0x65, 0x64,
        0x20, 0x4d, 0x65, 0x73, 0x73, 0x61, 0x67, 0x65,
        0x3a, 0x0a, 0x33, 0x32
    ];
    let mut eip191_msg: [u8; 60] = [0; 60];
    for i in 0..28 { eip191_msg[i] = eip191_prefix[i]; }
    for i in 0..32 { eip191_msg[28 + i] = challenge[i]; }
    let msg_hash = keccak256(eip191_msg, 60);

    // Step 4: secp256k1 signature verification
    let sig_valid = ecdsa_secp256k1::verify_signature(pubkey_x, pubkey_y, sig, msg_hash);
    assert(sig_valid, "M2 benchmark: secp256k1 EIP-191 signature verification failed");
}

// ---------------------------------------------------------------------------
// Test vectors (secp256k1 generator point G, privkey = 1)
// ---------------------------------------------------------------------------

// Returns pubkey_x for the generator point G (privkey = 1).
fn test_pubkey_x() -> [u8; 32] {
    [
        0x79, 0xbe, 0x66, 0x7e, 0xf9, 0xdc, 0xbb, 0xac, 0x55, 0xa0, 0x62, 0x95, 0xce, 0x87, 0x0b, 0x07,
        0x02, 0x9b, 0xfc, 0xdb, 0x2d, 0xce, 0x28, 0xd9, 0x59, 0xf2, 0x81, 0x5b, 0x16, 0xf8, 0x17, 0x98,
    ]
}

// Returns pubkey_y for the generator point G (privkey = 1).
fn test_pubkey_y() -> [u8; 32] {
    [
        0x48, 0x3a, 0xda, 0x77, 0x26, 0xa3, 0xc4, 0x65, 0x5d, 0xa4, 0xfb, 0xfc, 0x0e, 0x11, 0x08, 0xa8,
        0xfd, 0x17, 0xb4, 0x48, 0xa6, 0x85, 0x54, 0x19, 0x9c, 0x47, 0xd0, 0x8f, 0xfb, 0x10, 0xd4, 0xb8,
    ]
}

// Returns the M2 challenge: sha256(0x00*32 || 0x00*32) — simulates zero title_hash + zero root.
fn test_challenge() -> [u8; 32] {
    // sha256(64 zero bytes) = f5a5fd42d16a20302798ef6ed309979b43003d2320d9f0e8ea9831a92759fb4b
    let zeros = [0u8; 64];
    sha256_var(zeros, 64)
}

// Returns the RFC 6979 deterministic sig (r||s, 64 bytes) for privkey=1 over test_challenge().
// s is normalized to low-S form (s <= n/2) as required by Barretenberg's secp256k1 verifier.
// Python derivation: s_orig = 0xb3ee5d...; s_norm = n - s_orig = 0x4c11a2...
fn test_sig() -> [u8; 64] {
    [
        // r (32 bytes): 89ef25e7181bfb53cd4ecc8f0c12ed103fc4538b155885e5ee2998cc1257fdde
        0x89, 0xef, 0x25, 0xe7, 0x18, 0x1b, 0xfb, 0x53, 0xcd, 0x4e, 0xcc, 0x8f, 0x0c, 0x12, 0xed, 0x10,
        0x3f, 0xc4, 0x53, 0x8b, 0x15, 0x58, 0x85, 0xe5, 0xee, 0x29, 0x98, 0xcc, 0x12, 0x57, 0xfd, 0xde,
        // s (32 bytes, low-S normalized): 4c11a27cc9794bcb6a739a381cf1612e521d0a9432f76bef325e603d75d662b5
        0x4c, 0x11, 0xa2, 0x7c, 0xc9, 0x79, 0x4b, 0xcb, 0x6a, 0x73, 0x9a, 0x38, 0x1c, 0xf1, 0x61, 0x2e,
        0x52, 0x1d, 0x0a, 0x94, 0x32, 0xf7, 0x6b, 0xef, 0x32, 0x5e, 0x60, 0x3d, 0x75, 0xd6, 0x62, 0xb5,
    ]
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

// A valid (privkey=1, challenge=sha256(zeros)) signature passes verification.
// This confirms the M2 circuit step 3 accepts a legitimate key owner.
#[test]
fn valid_sig_passes_verification() {
    let pubkey_x = test_pubkey_x();
    let pubkey_y = test_pubkey_y();
    let sig = test_sig();
    let challenge = test_challenge();

    let is_valid = ecdsa_secp256k1::verify_signature(pubkey_x, pubkey_y, sig, challenge);
    assert(is_valid, "valid secp256k1 signature should pass verification");
}

// A garbage signature (all zeros) fails verification — simulates an attacker
// who has the public snapshot but not the holder's private key.
#[test]
fn invalid_sig_fails_verification() {
    let pubkey_x = test_pubkey_x();
    let pubkey_y = test_pubkey_y();
    let zero_sig: [u8; 64] = [0u8; 64];
    let challenge = test_challenge();

    let is_valid = ecdsa_secp256k1::verify_signature(pubkey_x, pubkey_y, zero_sig, challenge);
    // An all-zero (r, s) signature is not a valid ECDSA signature.
    assert(!is_valid, "all-zero signature should not pass verification");
}

// A valid signature verified against a wrong public key fails.
// Simulates: attacker substitutes their own pubkey for the holder's.
// The circuit derives hash160 from the witness pubkey; if the sig doesn't
// match that pubkey, the secp256k1 check fails before hash160 is used.
#[test]
fn valid_sig_wrong_pubkey_fails() {
    // Correct sig for G (privkey=1)
    let sig = test_sig();
    let challenge = test_challenge();

    // Wrong pubkey: flip one byte of x — not the generator point
    let mut wrong_x: [u8; 32] = test_pubkey_x();
    wrong_x[0] = 0x7a; // was 0x79
    let pubkey_y = test_pubkey_y();

    let is_valid = ecdsa_secp256k1::verify_signature(wrong_x, pubkey_y, sig, challenge);
    // The sig was made with privkey=1 (G); it should not verify under a different pubkey.
    assert(!is_valid, "valid sig should not verify under the wrong public key");
}

// ---------------------------------------------------------------------------
// Encoding-fix regression test (tick-4009)
// ---------------------------------------------------------------------------
//
// Context: cast_vote_babylon_v2 computes
//   challenge = sha256( title_hash_encoded[32] || root_bytes[32] )
//
// The fix (commit c9c5f83) changed the title_hash encoding from
// encode_field_as_root (31 bytes + 0x00 pad) to to_be_bytes::<32>() (full 32 bytes).
// For BN254 field elements >= 2^248 (~97.9% of all poseidon2 hashes), byte[0] is
// non-zero, so encode_field_as_root silently drops it, producing a different challenge
// than the TypeScript fieldToBytes32 — causing ECDSA rejection for ~97.9% of votes.
//
// This test uses title_hash_bytes32 = 0x2faabb...19 (high byte = 0x2f, non-zero).
// The sig is valid only for challenge = sha256(title_correct || zeros32).
// Using the OLD encode_field_as_root output (byte[0] = 0x00 instead of 0x2f) would
// produce a different challenge and the verification would fail.
//
// Test vectors generated by Python (ecdsa library, RFC 6979 deterministic, privkey=1).

// Returns title_hash_bytes32 with high byte = 0x2f (non-zero — tests encoding fix).
// In the circuit, this comes from config.title_hash.to_be_bytes() after the fix.
// Before the fix, encode_field_as_root would have produced [0x00, 0xaa, 0xbb, ...].
fn encoding_test_title_bytes() -> [u8; 32] {
    [
        0x2f, 0xaa, 0xbb, 0xcc, 0xdd, 0xee, 0xff, 0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08, 0x09,
        0x0a, 0x0b, 0x0c, 0x0d, 0x0e, 0x0f, 0x10, 0x11, 0x12, 0x13, 0x14, 0x15, 0x16, 0x17, 0x18, 0x19,
    ]
}

// Returns the wrong title encoding from encode_field_as_root: byte[0] = 0x00.
// This is what the OLD circuit produced, silently dropping the 0x2f high byte.
fn encoding_test_title_bytes_wrong() -> [u8; 32] {
    [
        0x00, 0xaa, 0xbb, 0xcc, 0xdd, 0xee, 0xff, 0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08, 0x09,
        0x0a, 0x0b, 0x0c, 0x0d, 0x0e, 0x0f, 0x10, 0x11, 0x12, 0x13, 0x14, 0x15, 0x16, 0x17, 0x18, 0x19,
    ]
}

// Returns the RFC 6979 sig (r||s, low-S) for privkey=1 over:
//   challenge = sha256([0x2f, 0xaa, 0xbb, ..., 0x19] || [0x00*32])
//             = 778cd3360542b8ec90434ab1d6aaa5f68b780b012e425b3c132a598d2c2901ac
fn encoding_test_sig() -> [u8; 64] {
    [
        // r: bb2619966aad8787ee4e1bef42539689527535e60bc2037bac9be57edd0e7f19
        0xbb, 0x26, 0x19, 0x96, 0x6a, 0xad, 0x87, 0x87, 0xee, 0x4e, 0x1b, 0xef, 0x42, 0x53, 0x96, 0x89,
        0x52, 0x75, 0x35, 0xe6, 0x0b, 0xc2, 0x03, 0x7b, 0xac, 0x9b, 0xe5, 0x7e, 0xdd, 0x0e, 0x7f, 0x19,
        // s (low-S): 747456b62fb713cd373cd74b7f23c7da8fb8250343cb849de5f2c0cad507d56e
        0x74, 0x74, 0x56, 0xb6, 0x2f, 0xb7, 0x13, 0xcd, 0x37, 0x3c, 0xd7, 0x4b, 0x7f, 0x23, 0xc7, 0xda,
        0x8f, 0xb8, 0x25, 0x03, 0x43, 0xcb, 0x84, 0x9d, 0xe5, 0xf2, 0xc0, 0xca, 0xd5, 0x07, 0xd5, 0x6e,
    ]
}

// The correct challenge: sha256(title_correct[32] || zeros[32]).
// = 778cd3360542b8ec90434ab1d6aaa5f68b780b012e425b3c132a598d2c2901ac
// Computed in Python with the full 32-byte title encoding.
fn encoding_test_challenge_correct() -> [u8; 32] {
    let title = encoding_test_title_bytes();
    let zeros = [0u8; 32];
    let mut input = [0u8; 64];
    for i in 0..32 { input[i] = title[i]; }
    for i in 0..32 { input[32 + i] = zeros[i]; }
    sha256_var(input, 64)
}

// The wrong challenge: sha256(title_wrong[32] || zeros[32]).
// = 496aa2abda987195c1b95a0be9f12fc2a64c3c54655e9077e6623132ef849137
// The OLD encode_field_as_root path would have produced this for the same title_hash.
fn encoding_test_challenge_wrong() -> [u8; 32] {
    let title = encoding_test_title_bytes_wrong(); // byte[0] = 0x00 instead of 0x2f
    let zeros = [0u8; 32];
    let mut input = [0u8; 64];
    for i in 0..32 { input[i] = title[i]; }
    for i in 0..32 { input[32 + i] = zeros[i]; }
    sha256_var(input, 64)
}

// Regression test: sig computed for the CORRECT challenge (high byte preserved)
// verifies successfully — this is the expected path after the encoding fix.
#[test]
fn encoding_fix_correct_challenge_passes() {
    let pubkey_x = test_pubkey_x();
    let pubkey_y = test_pubkey_y();
    let sig = encoding_test_sig();
    let challenge = encoding_test_challenge_correct();

    let is_valid = ecdsa_secp256k1::verify_signature(pubkey_x, pubkey_y, sig, challenge);
    assert(is_valid, "sig should verify against correct (high-byte-preserved) challenge");
}

// Regression test: the SAME sig (for the correct challenge) FAILS against the
// wrong challenge that encode_field_as_root would have produced (byte[0] = 0x00).
// This confirms the two encoding paths produce distinct challenges for high-byte
// title_hash values, and that the fix is necessary — not an accidental no-op.
#[test]
fn encoding_fix_wrong_challenge_fails() {
    let pubkey_x = test_pubkey_x();
    let pubkey_y = test_pubkey_y();
    let sig = encoding_test_sig();
    let challenge = encoding_test_challenge_wrong(); // OLD encode_field_as_root path

    let is_valid = ecdsa_secp256k1::verify_signature(pubkey_x, pubkey_y, sig, challenge);
    // The sig was created for challenge_correct; it must not verify against challenge_wrong.
    // If this test ever fails (is_valid = true), the two challenges are accidentally equal,
    // which would mean the fix was a no-op — an unexpected collision.
    assert(!is_valid, "sig must not verify against the old encode_field_as_root challenge (non-zero high byte dropped)");
}

// A valid sig verified against a different message (different challenge) fails.
// Simulates a replay attack: attacker tries to reuse a sig from a different vote.
#[test]
fn valid_sig_wrong_challenge_fails() {
    let pubkey_x = test_pubkey_x();
    let pubkey_y = test_pubkey_y();
    let sig = test_sig();

    // Different challenge: sha256(0x01 || zeros[63]) — different title_hash / root
    let mut diff_input = [0u8; 64];
    diff_input[0] = 0x01;
    let diff_challenge = sha256_var(diff_input, 64);

    let is_valid = ecdsa_secp256k1::verify_signature(pubkey_x, pubkey_y, sig, diff_challenge);
    assert(!is_valid, "sig should not verify against a different challenge (replay protection)");
}

